describe('truncateContent', () => {
  it('should handle happy path', () => {
    const longText = 'The quick brown fox jumps over the lazy dog near the riverbank';
    const result = truncateContent(longText, 20);
    expect(result).toBe('The quick brown f...');
  });

  it('should handle edge case', () => {
    // Edge case: maxLength less than 3, should return empty string or ellipsis
    const text = 'Hello';
    const result = truncateContent(text, 2);
    expect(result).toBe('');
  });

  it('should handle null/empty', () => {
    const result1 = truncateContent(null, 10);
    const result2 = truncateContent(undefined, 10);
    const result3 = truncateContent('', 10);
    const result4 = truncateContent('Test', 0);
    expect(result1).toBe('');
    expect(result2).toBe('');
    expect(result3).toBe('');
    expect(result4).toBe('');
  });
});

