import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

// Assume the module exporting handleDelete is './deleteHandler'
vi.mock('./noteService', () => ({
  deleteNote: vi.fn(),
}));
import { deleteNote } from './noteService';
import { handleDelete } from './deleteHandler';

describe('handleDelete', () => {
  let originalPreventDefault: any;

  beforeEach(() => {
    // Reset mock state before each test
    vi.clearAllMocks();
    // Mock preventDefault function
    originalPreventDefault = globalThis.Event?.prototype?.preventDefault;
    globalThis.Event?.prototype?.preventDefault = vi.fn();
  });

  afterEach(() => {
    // Restore original preventDefault
    if (originalPreventDefault) {
      globalThis.Event?.prototype?.preventDefault = originalPreventDefault;
    }
  });

  it('should handle happy path and delete note correctly', () => {
    const mockEvent = {
      preventDefault: vi.fn(),
      target: {
        dataset: { id: '123' },
      },
    } as unknown as Event;

    handleDelete(mockEvent as Event);

    expect(mockEvent.preventDefault).toHaveBeenCalled();
    expect(deleteNote).toHaveBeenCalledWith('123');
  });

  it('should handle edge case with zero or empty string id gracefully', () => {
    const mockEventZero = {
      preventDefault: vi.fn(),
      target: {
        dataset: { id: '0' },
      },
    } as unknown as Event;

    const mockEventEmpty = {
      preventDefault: vi.fn(),
      target: {
        dataset: { id: '' },
      },
    } as unknown as Event;

    // Should still call deleteNote with the provided id
    handleDelete(mockEventZero as Event);
    expect(deleteNote).toHaveBeenCalledWith('0');

    handleDelete(mockEventEmpty as Event);
    expect(deleteNote).toHaveBeenCalledWith('');
  });

  it('should handle null/empty event without throwing', () => {
    const nullEvent = null as unknown as Event;
    const undefinedEvent = undefined as unknown as Event;
    const emptyObjectEvent = {} as unknown as Event;

    expect(() => handleDelete(nullEvent)).not.toThrow();
    expect(() => handleDelete(undefinedEvent)).not.toThrow();
    expect(() => handleDelete(emptyObjectEvent)).not.toThrow();
  });
});